{
  "name": "filebrowser-ui",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "build": "tsc && node scripts/copy-assets.mjs",
    "test": "vitest run",
    "watch": "tsc --watch"
  },
  "devDependencies": {
    "typescript": "^5.6.3",
    "vitest": "^2.1.4",
    "happy-dom": "^15.7.4"
  }
}

import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    environment: 'happy-dom',
    include: ['src/**/*.test.ts']
  }
});

export interface FileEntry {
  name: string;
  path: string;
  isDirectory: boolean;
  size: number;
  lastModified: string;
}

export interface BrowseResult {
  path: string;
  parent: string | null;
  entries: FileEntry[];
  folderCount: number;
  fileCount: number;
  totalSize: number;
}

export interface SearchResult {
  query: string;
  path: string;
  results: FileEntry[];
}

export class ApiClient {
  constructor(private readonly baseUrl: string = '/api/files') {}

  async browse(path: string): Promise<BrowseResult> {
    return this.request<BrowseResult>(
      `${this.baseUrl}/browse?path=${encodeURIComponent(path)}`,
      { method: 'GET' }
    );
  }

  async search(query: string, path: string): Promise<SearchResult> {
    return this.request<SearchResult>(
      `${this.baseUrl}/search?query=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`,
      { method: 'GET' }
    );
  }

  async upload(path: string, file: File): Promise<{ path: string }> {
    const formData = new FormData();
    formData.append('file', file);
    return this.request<{ path: string }>(
      `${this.baseUrl}/upload?path=${encodeURIComponent(path)}`,
      { method: 'POST', body: formData }
    );
  }

  async delete(path: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/delete?path=${encodeURIComponent(path)}`,
      { method: 'DELETE' }
    );
  }

  async move(source: string, destination: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/move`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
      }
    );
  }

  async copy(source: string, destination: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/copy`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
      }
    );
  }

  downloadUrl(path: string): string {
    return `${this.baseUrl}/download?path=${encodeURIComponent(path)}`;
  }

  private async request<T>(url: string, init?: RequestInit): Promise<T> {
    const res = await fetch(url, init);
    if (!res.ok) {
      throw new Error(res.status + ': ' + await res.text());
    }
    return await res.json() as T;
  }
}

export type View = 'browse' | 'search';

export interface Route {
  view: View;
  path: string;
  query: string;
}

const DEFAULT_ROUTE: Route = { view: 'browse', path: '', query: '' };

/**
 * Parse a full hash (including leading '#') into a Route.
 *
 * Browse format:  #/browse  or  #/browse/<segments>
 * Search format:  #/search?q=<query>&path=<path>
 * Anything else returns the default browse route.
 */
export function parseHash(hash: string): Route {
  if (hash.startsWith('#/browse')) {
    const afterPrefix = hash.slice('#/browse'.length); // everything after "#/browse"
    // Remove the leading '/' if present, then URL-decode what remains
    const path = afterPrefix.startsWith('/')
      ? decodeURIComponent(afterPrefix.slice(1))
      : decodeURIComponent(afterPrefix);
    return { view: 'browse', path, query: '' };
  }

  if (hash.startsWith('#/search')) {
    const queryString = hash.slice('#/search'.length);
    const params = new URLSearchParams(queryString);
    const query = params.get('q') ?? '';
    const path = params.get('path') ?? '';
    return { view: 'search', query, path };
  }

  return DEFAULT_ROUTE;
}

/**
 * Serialize a browse path into a browse hash.
 * Each segment is independently percent-encoded.
 */
export function toBrowseHash(path: string): string {
  if (path === '') {
    return '#/browse';
  }
  const segments = path.split('/');
  const encoded = segments.map((s) => encodeURIComponent(s)).join('/');
  return '#/browse/' + encoded;
}

/**
 * Serialize query and path values into a search hash.
 * Both values are percent-encoded.
 */
export function toSearchHash(query: string, path: string): string {
  return `#/search?q=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`;
}

/**
 * Read the current route from window.location.hash.
 */
export function getCurrentRoute(): Route {
  return parseHash(window.location.hash);
}

/**
 * Subscribe to hash-change events.
 * Returns an unsubscribe function.
 */
export function subscribe(callback: () => void): () => void {
  window.addEventListener('hashchange', callback);
  return () => {
    window.removeEventListener('hashchange', callback);
  };
}

/**
 * Navigate to a given hash (sets window.location.hash).
 */
export function navigate(hash: string): void {
  window.location.hash = hash;
}

/**
 * Pure formatting helpers for the file browser UI.
 *
 * Every function in this module is side-effect free (no DOM access, no network)
 * so each can be unit-tested in isolation. The module exports ONLY the six
 * functions declared here.
 */

/** Binary (1024-based) byte-unit suffixes, from bytes up to terabytes. */
const BYTE_UNITS = ["B", "KB", "MB", "GB", "TB"] as const;

/**
 * Format a byte count as a human-readable string using binary (1024-based)
 * units.
 *
 * - Values below 1024 render as an integer byte count, e.g. `0 B`, `1023 B`.
 * - Values of 1024 and above render with exactly one decimal place, keeping a
 *   trailing `.0`, e.g. `1.0 KB`, `1.5 KB`, `1.0 MB`.
 *
 * The unit caps at `TB`; values beyond 1024 TB remain expressed in terabytes.
 */
export function formatBytes(bytes: number): string {
    const units = BYTE_UNITS;
    let value = bytes;
    let unitIndex = 0;

    while (value >= 1024 && unitIndex < units.length - 1) {
        value /= 1024;
        unitIndex++;
    }

    if (unitIndex === 0) {
        // Below the KB boundary: render as an integer byte count.
        return `${Math.round(value)} ${units[unitIndex]}`;
    }

    // KB and above: one decimal place (trailing .0 preserved per spec).
    return `${value.toFixed(1)} ${units[unitIndex]}`;
}

/**
 * Normalize a relative path into a clean, slash-joined form.
 *
 * - backslashes (`\`) become forward slashes
 * - leading/trailing slashes are trimmed
 * - runs of repeated slashes collapse to one
 * - `.` and `..` segments are dropped (filtered out, NOT resolved against the
 *   parent — this also neutralizes path-traversal segments)
 * - empty/root input collapses to `""`
 */
export function normalizeRelativePath(path: string): string {
    return path
        .replace(/\\/g, "/")
        .split("/")
        .filter((segment) => segment !== "" && segment !== "." && segment !== "..")
        .join("/");
}

/**
 * Join two path fragments with a single separating slash, then normalize the
 * result (see {@link normalizeRelativePath}).
 */
export function joinPath(base: string, name: string): string {
    return normalizeRelativePath(`${base}/${name}`);
}

/**
 * Return the normalized parent relative path, or `""` when the path is already
 * at root (empty or a single segment after normalization).
 */
export function parentPath(path: string): string {
    const normalized = normalizeRelativePath(path);
    const lastSlash = normalized.lastIndexOf("/");
    return lastSlash === -1 ? "" : normalized.slice(0, lastSlash);
}

/**
 * Return the last segment of a normalized path. Returns `""` for an empty
 * path.
 */
export function basename(path: string): string {
    const normalized = normalizeRelativePath(path);
    const lastSlash = normalized.lastIndexOf("/");
    return lastSlash === -1 ? normalized : normalized.slice(lastSlash + 1);
}

/** Left-pad a number to two digits with a leading zero. */
function padTwo(value: number): string {
    return String(value).padStart(2, "0");
}

/**
 * Format an ISO 8601 date string as `yyyy-MM-dd HH:mm` (local calendar time).
 *
 * Returns `""` for empty or unparseable input instead of throwing.
 */
export function formatDate(iso: string): string {
    if (!iso) {
        return "";
    }

    const date = new Date(iso);
    if (Number.isNaN(date.getTime())) {
        return "";
    }

    const year = date.getFullYear();
    const month = padTwo(date.getMonth() + 1);
    const day = padTwo(date.getDate());
    const hours = padTwo(date.getHours());
    const minutes = padTwo(date.getMinutes());

    return `${year}-${month}-${day} ${hours}:${minutes}`;
}

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { ApiClient, type FileEntry, type BrowseResult, type SearchResult } from './api';

/**
 * Builds a minimal fetch Response stand-in for the mocked global fetch.
 * `json()` returns the parsed body; `text()` returns the raw text (defaults to
 * the JSON-stringified body). `ok` is derived from status unless overridden.
 */
function mockResponse(opts: {
  ok?: boolean;
  status?: number;
  body?: unknown;
  text?: string;
}): Response {
  const status = opts.status ?? 200;
  const ok = opts.ok ?? (status >= 200 && status < 300);
  const text = opts.text ?? JSON.stringify(opts.body ?? {});
  return {
    ok,
    status,
    text: async () => text,
    json: async () => (opts.body ?? (opts.text ? JSON.parse(opts.text) : {})),
  } as unknown as Response;
}

describe('ApiClient', () => {
  let fetchMock: ReturnType<typeof vi.fn>;

  beforeEach(() => {
    fetchMock = vi.fn();
    vi.stubGlobal('fetch', fetchMock);
  });

  afterEach(() => {
    vi.unstubAllGlobals();
    vi.restoreAllMocks();
  });

  describe('constructor', () => {
    it('defaults baseUrl to /api/files', () => {
      const client = new ApiClient();
      expect(client.downloadUrl('x')).toBe('/api/files/download?path=x');
    });

    it('honors a custom baseUrl', () => {
      const client = new ApiClient('/custom/api');
      expect(client.downloadUrl('x')).toBe('/custom/api/download?path=x');
    });
  });

  describe('browse', () => {
    it('GETs the browse endpoint with an encoded path and returns parsed JSON', async () => {
      const client = new ApiClient();
      const entries: FileEntry[] = [
        { name: 'a.txt', path: '/root/a.txt', isDirectory: false, size: 10, lastModified: '2024-01-01T00:00:00Z' },
      ];
      const result: BrowseResult = {
        path: '/root',
        parent: '/',
        entries,
        folderCount: 0,
        fileCount: 1,
        totalSize: 10,
      };
      fetchMock.mockResolvedValueOnce(mockResponse({ body: result }));

      const data = await client.browse('/root');

      expect(fetchMock).toHaveBeenCalledTimes(1);
      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/browse?path=' + encodeURIComponent('/root'));
      expect(init?.method).toBe('GET');
      expect(data).toEqual(result);
    });

    it('encodes special characters in the path', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(
        mockResponse({ body: { path: '', parent: null, entries: [], folderCount: 0, fileCount: 0, totalSize: 0 } })
      );
      const tricky = '/foo bar/baz?x=1&y=2';
      await client.browse(tricky);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/browse?path=' + encodeURIComponent(tricky));
    });

    it('throws an Error containing status and response text on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 404, text: 'Not Found' }));

      await expect(client.browse('/missing')).rejects.toThrow('404: Not Found');
      await expect(client.browse('/missing')).rejects.toBeInstanceOf(Error);
    });

    it('throws a plain Error instance (not a string) on failure', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValue(mockResponse({ status: 500, text: 'boom' }));
      await expect(client.browse('/x')).rejects.toBeInstanceOf(Error);
    });
  });

  describe('search', () => {
    it('GETs the search endpoint with encoded query and path and returns parsed JSON', async () => {
      const client = new ApiClient();
      const results: FileEntry[] = [
        { name: 'match.txt', path: '/root/match.txt', isDirectory: false, size: 5, lastModified: '2024-02-02T00:00:00Z' },
      ];
      const out: SearchResult = { query: 'mat', path: '/root', results };
      fetchMock.mockResolvedValueOnce(mockResponse({ body: out }));

      const data = await client.search('mat', '/root');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe(
        '/api/files/search?query=' + encodeURIComponent('mat') + '&path=' + encodeURIComponent('/root')
      );
      expect(init?.method).toBe('GET');
      expect(data).toEqual(out);
    });

    it('encodes special characters in both query and path', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(
        mockResponse({ body: { query: '', path: '', results: [] } })
      );
      const q = 'a b&c';
      const p = '/dir x/y?z=1';
      await client.search(q, p);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/search?query=' + encodeURIComponent(q) + '&path=' + encodeURIComponent(p));
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 400, text: 'Bad Request' }));
      await expect(client.search('q', '/p')).rejects.toThrow('400: Bad Request');
    });
  });

  describe('upload', () => {
    it('POSTs multipart form data with a file field named "file" and returns parsed JSON', async () => {
      const client = new ApiClient();
      const file = new File(['hello'], 'hello.txt', { type: 'text/plain' });
      fetchMock.mockResolvedValueOnce(mockResponse({ body: { path: '/root/hello.txt' } }));

      const data = await client.upload('/root', file);

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/upload?path=' + encodeURIComponent('/root'));
      expect(init?.method).toBe('POST');
      const body = init?.body;
      expect(body).toBeInstanceOf(FormData);
      expect((body as FormData).get('file')).toBe(file);
      expect(data).toEqual({ path: '/root/hello.txt' });
    });

    it('encodes the destination path in the query string', async () => {
      const client = new ApiClient();
      const file = new File(['x'], 'x.txt');
      fetchMock.mockResolvedValueOnce(mockResponse({ body: { path: '' } }));
      const dest = '/some dir/sub?x=1';
      await client.upload(dest, file);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/upload?path=' + encodeURIComponent(dest));
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      const file = new File(['x'], 'x.txt');
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 413, text: 'Too Large' }));
      await expect(client.upload('/root', file)).rejects.toThrow('413: Too Large');
    });
  });

  describe('delete', () => {
    it('issues a DELETE to the delete endpoint and resolves to void on success', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 204, body: null }));

      const result = await client.delete('/root/old.txt');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/delete?path=' + encodeURIComponent('/root/old.txt'));
      expect(init?.method).toBe('DELETE');
      expect(result).toBeUndefined();
    });

    it('encodes the path', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 204 }));
      const p = '/a b/c?d=1';
      await client.delete(p);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/delete?path=' + encodeURIComponent(p));
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 403, text: 'Forbidden' }));
      await expect(client.delete('/nope')).rejects.toThrow('403: Forbidden');
    });
  });

  describe('move', () => {
    it('POSTs JSON { sourcePath, destinationPath } with Content-Type application/json and resolves void', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200, body: {} }));

      const result = await client.move('/a/b.txt', '/c/b.txt');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/move');
      expect(init?.method).toBe('POST');
      const headers = init?.headers as Record<string, string>;
      expect(headers['Content-Type']).toBe('application/json');
      expect(JSON.parse(init!.body as string)).toEqual({ sourcePath: '/a/b.txt', destinationPath: '/c/b.txt' });
      expect(result).toBeUndefined();
    });

    it('does not encode paths because they ride in a JSON body', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200 }));
      await client.move('/a b/c?x=1', '/d e/f?y=2');
      const body = JSON.parse(fetchMock.mock.calls[0][1].body as string);
      expect(body).toEqual({ sourcePath: '/a b/c?x=1', destinationPath: '/d e/f?y=2' });
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 409, text: 'Conflict' }));
      await expect(client.move('/a', '/b')).rejects.toThrow('409: Conflict');
    });
  });

  describe('copy', () => {
    it('POSTs JSON { sourcePath, destinationPath } with Content-Type application/json and resolves void', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200, body: {} }));

      const result = await client.copy('/a/b.txt', '/c/b.txt');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/copy');
      expect(init?.method).toBe('POST');
      const headers = init?.headers as Record<string, string>;
      expect(headers['Content-Type']).toBe('application/json');
      expect(JSON.parse(init!.body as string)).toEqual({ sourcePath: '/a/b.txt', destinationPath: '/c/b.txt' });
      expect(result).toBeUndefined();
    });

    it('sends the raw paths in the JSON body', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200 }));
      await client.copy('/src dir/f?x=1', '/dst dir/g?y=2');
      const body = JSON.parse(fetchMock.mock.calls[0][1].body as string);
      expect(body).toEqual({ sourcePath: '/src dir/f?x=1', destinationPath: '/dst dir/g?y=2' });
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 500, text: 'Server Error' }));
      await expect(client.copy('/a', '/b')).rejects.toThrow('500: Server Error');
    });
  });

  describe('downloadUrl', () => {
    it('returns the encoded download URL synchronously without calling fetch', () => {
      const client = new ApiClient();
      const url = client.downloadUrl('/root/file.txt');
      expect(url).toBe('/api/files/download?path=' + encodeURIComponent('/root/file.txt'));
      expect(fetchMock).not.toHaveBeenCalled();
    });

    it('encodes special characters', () => {
      const client = new ApiClient();
      const tricky = '/a b/c?d=1&e=2';
      expect(client.downloadUrl(tricky)).toBe('/api/files/download?path=' + encodeURIComponent(tricky));
    });

    it('respects a custom baseUrl', () => {
      const client = new ApiClient('/api/v2/files');
      expect(client.downloadUrl('x')).toBe('/api/v2/files/download?path=x');
    });
  });

  describe('shared response types', () => {
    it('FileEntry shape matches the DTO contract', () => {
      const entry: FileEntry = {
        name: 'file.txt',
        path: '/root/file.txt',
        isDirectory: false,
        size: 123,
        lastModified: '2024-01-01T00:00:00Z',
      };
      expect(entry.name).toBe('file.txt');
      expect(entry.isDirectory).toBe(false);
    });

    it('BrowseResult shape matches the DTO contract including nullable parent', () => {
      const result: BrowseResult = {
        path: '/root',
        parent: null,
        entries: [],
        folderCount: 0,
        fileCount: 0,
        totalSize: 0,
      };
      expect(result.parent).toBeNull();
      expect(Array.isArray(result.entries)).toBe(true);
    });

    it('SearchResult shape matches the DTO contract', () => {
      const result: SearchResult = {
        query: 'foo',
        path: '/root',
        results: [
          { name: 'foo.txt', path: '/root/foo.txt', isDirectory: false, size: 1, lastModified: '2024-01-01T00:00:00Z' },
        ],
      };
      expect(result.results).toHaveLength(1);
    });
  });
});

// @vitest-environment node

/**
 * Pure-function tests for the router's parsers and serializers.
 *
 * This file is pinned to the `node` environment (see the docblock above) on
 * purpose: the spec requires the pure helpers to be "unit-testable without a
 * DOM". Running them here — with no `window`, `document`, or happy-dom shim
 * available — guarantees that `parseHash`, `toBrowseHash`, and `toSearchHash`
 * (and therefore their importing module at load time) introduce no DOM
 * dependency. The DOM-bound helpers are covered separately in
 * `router.dom.test.ts`.
 */
import { describe, it, expect } from 'vitest';
import {
  parseHash,
  toBrowseHash,
  toSearchHash,
  type Route,
  type View,
} from './router';

const DEFAULT_ROUTE: Route = { view: 'browse', path: '', query: '' };

describe('parseHash', () => {
  describe('browse routes', () => {
    it('parses #/browse with no segments to an empty path', () => {
      expect(parseHash('#/browse')).toEqual(DEFAULT_ROUTE);
    });

    it('parses #/browse/ (trailing slash, no segments) to an empty path', () => {
      expect(parseHash('#/browse/')).toEqual(DEFAULT_ROUTE);
    });

    it('parses a single segment', () => {
      expect(parseHash('#/browse/docs')).toEqual({ view: 'browse', path: 'docs', query: '' });
    });

    it('joins multiple segments with /', () => {
      expect(parseHash('#/browse/docs/2024/reports')).toEqual({
        view: 'browse',
        path: 'docs/2024/reports',
        query: '',
      });
    });

    it('URL-decodes percent-encoded characters', () => {
      expect(parseHash('#/browse/hello%20world')).toEqual({
        view: 'browse',
        path: 'hello world',
        query: '',
      });
    });

    it('decodes each segment independently', () => {
      expect(parseHash('#/browse/a%20b/c%20d')).toEqual({
        view: 'browse',
        path: 'a b/c d',
        query: '',
      });
    });

    it('decodes an encoded slash (%2F) within a segment', () => {
      expect(parseHash('#/browse/sub%2Ffolder')).toEqual({
        view: 'browse',
        path: 'sub/folder',
        query: '',
      });
    });

    it('preserves a trailing slash in the decoded path', () => {
      expect(parseHash('#/browse/docs/')).toEqual({ view: 'browse', path: 'docs/', query: '' });
    });

    it('decodes multi-byte (unicode) percent sequences', () => {
      // 'café' encoded as UTF-8
      expect(parseHash('#/browse/caf%C3%A9')).toEqual({
        view: 'browse',
        path: 'café',
        query: '',
      });
    });
  });

  describe('search routes', () => {
    it('parses both query and path params', () => {
      expect(parseHash('#/search?q=hello&path=docs')).toEqual({
        view: 'search',
        query: 'hello',
        path: 'docs',
      });
    });

    it('defaults path to an empty string when absent', () => {
      expect(parseHash('#/search?q=hello')).toEqual({
        view: 'search',
        query: 'hello',
        path: '',
      });
    });

    it('defaults query to an empty string when absent', () => {
      expect(parseHash('#/search?path=docs')).toEqual({
        view: 'search',
        query: '',
        path: 'docs',
      });
    });

    it('treats #/search with no query string as an empty search', () => {
      expect(parseHash('#/search')).toEqual({ view: 'search', query: '', path: '' });
    });

    it('treats #/search? (bare question mark) as an empty search', () => {
      expect(parseHash('#/search?')).toEqual({ view: 'search', query: '', path: '' });
    });

    it('treats an explicitly empty q= as an empty query', () => {
      expect(parseHash('#/search?q=')).toEqual({ view: 'search', query: '', path: '' });
    });

    it('treats an explicitly empty path= as an empty path', () => {
      expect(parseHash('#/search?q=hi&path=')).toEqual({
        view: 'search',
        query: 'hi',
        path: '',
      });
    });

    it('URL-decodes encoded query and path values', () => {
      expect(parseHash('#/search?q=hello%20world&path=my%20docs')).toEqual({
        view: 'search',
        query: 'hello world',
        path: 'my docs',
      });
    });

    it('decodes a "+" in the query as a space (URLSearchParams behavior)', () => {
      expect(parseHash('#/search?q=hello+world&path=x')).toEqual({
        view: 'search',
        query: 'hello world',
        path: 'x',
      });
    });

    it('keeps an unencoded slash in path= intact', () => {
      expect(parseHash('#/search?q=a&path=docs/2024')).toEqual({
        view: 'search',
        query: 'a',
        path: 'docs/2024',
      });
    });

    it('returns the first value when a param is repeated', () => {
      // URLSearchParams.get() yields the first occurrence.
      expect(parseHash('#/search?q=a&q=b&path=c')).toEqual({
        view: 'search',
        query: 'a',
        path: 'c',
      });
    });

    it('decodes multi-byte (unicode) values', () => {
      expect(parseHash('#/search?q=caf%C3%A9&path=%C3%B1')).toEqual({
        view: 'search',
        query: 'café',
        path: 'ñ',
      });
    });
  });

  describe('fallback for unrecognized hashes', () => {
    it.each<[string, string]>([
      ['an empty string', ''],
      ['a lone hash', '#'],
      ['a hash-slash only', '#/'],
      ['an unknown view', '#/home'],
      ['a string with no leading hash', 'garbage'],
      ['browse missing the leading slash (#browse)', '#browse'],
      ['a completely unrelated fragment', '#section-1'],
    ])('returns the default browse route for %s', (_label, hash) => {
      expect(parseHash(hash)).toEqual(DEFAULT_ROUTE);
    });
  });

  describe('returned shape', () => {
    it('always returns an object with exactly view, path, and query', () => {
      const route = parseHash('#/browse/a');
      expect(route).toHaveProperty('view');
      expect(route).toHaveProperty('path');
      expect(route).toHaveProperty('query');
      expect(Object.keys(route).sort()).toEqual(['path', 'query', 'view']);
    });

    it('produces view values assignable to the View union', () => {
      const browseView: View = parseHash('#/browse').view;
      const searchView: View = parseHash('#/search?q=a').view;
      expect([browseView, searchView]).toEqual(['browse', 'search']);
    });
  });
});

describe('toBrowseHash', () => {
  it('returns #/browse for an empty path', () => {
    expect(toBrowseHash('')).toBe('#/browse');
  });

  it('returns #/browse/<segment> for a single segment', () => {
    expect(toBrowseHash('docs')).toBe('#/browse/docs');
  });

  it('joins multiple segments with /', () => {
    expect(toBrowseHash('docs/2024/reports')).toBe('#/browse/docs/2024/reports');
  });

  it('percent-encodes spaces within a segment', () => {
    expect(toBrowseHash('hello world')).toBe('#/browse/hello%20world');
  });

  it('encodes each segment independently (spaces do not leak across segments)', () => {
    expect(toBrowseHash('a b/c d')).toBe('#/browse/a%20b/c%20d');
  });

  it('encodes reserved characters such as ? and #', () => {
    expect(toBrowseHash('a?b#c')).toBe('#/browse/a%3Fb%23c');
  });

  it('encodes a literal percent sign', () => {
    expect(toBrowseHash('100%')).toBe('#/browse/100%25');
  });

  it('preserves a trailing slash as an empty trailing segment', () => {
    expect(toBrowseHash('docs/')).toBe('#/browse/docs/');
  });

  it('encodes multi-byte (unicode) characters as UTF-8 percent sequences', () => {
    expect(toBrowseHash('café')).toBe('#/browse/caf%C3%A9');
  });
});

describe('toSearchHash', () => {
  it('builds a search hash from query and path', () => {
    expect(toSearchHash('hello', 'docs')).toBe('#/search?q=hello&path=docs');
  });

  it('handles empty query and path', () => {
    expect(toSearchHash('', '')).toBe('#/search?q=&path=');
  });

  it('percent-encodes spaces in both query and path', () => {
    expect(toSearchHash('hello world', 'my docs')).toBe(
      '#/search?q=hello%20world&path=my%20docs',
    );
  });

  it('encodes characters that would otherwise break the query string (& and =)', () => {
    expect(toSearchHash('a&b', 'c=d')).toBe('#/search?q=a%26b&path=c%3Dd');
  });

  it('encodes a literal percent sign', () => {
    expect(toSearchHash('100% off', 'x')).toBe('#/search?q=100%25%20off&path=x');
  });

  it('encodes a slash in the path so it survives a single path= param', () => {
    expect(toSearchHash('a', 'b/c')).toBe('#/search?q=a&path=b%2Fc');
  });

  it('encodes multi-byte (unicode) characters as UTF-8 percent sequences', () => {
    expect(toSearchHash('café', 'ñ')).toBe('#/search?q=caf%C3%A9&path=%C3%B1');
  });
});

/**
 * Round-trip property tests. These do not couple to a particular encoding
 * scheme: they assert the spec-level invariant that serializing a value and
 * parsing it back is lossless. They serve as a behavioral safety net on top of
 * the exact-format assertions above.
 */
describe('round-trip serialization (serialize -> parse is lossless)', () => {
  it.each([
    ['empty path', ''],
    ['single segment', 'docs'],
    ['multiple segments', 'docs/2024/reports'],
    ['spaces within segments', 'a b/c d'],
    ['reserved characters', 'a?b#c'],
    ['literal percent', '100%'],
    ['trailing slash', 'docs/'],
    ['unicode', 'café'],
  ])('round-trips browse path: %s', (_label, path) => {
    expect(parseHash(toBrowseHash(path))).toEqual({ view: 'browse', path, query: '' });
  });

  it.each<[string, string, string]>([
    ['empty query and path', '', ''],
    ['query only', 'hello', ''],
    ['path only', '', 'docs'],
    ['both values', 'hello world', 'my docs'],
    ['query-string-breaking chars', 'a&b', 'c=d'],
    ['plus character', 'a+b', 'c'],
    ['percent character', '100% off', 'a/b'],
    ['unicode', 'café', 'ñ'],
  ])('round-trips search route: %s', (_label, query, path) => {
    expect(parseHash(toSearchHash(query, path))).toEqual({ view: 'search', query, path });
  });
});

import { describe, it, expect } from 'vitest';
import * as formatModule from './format';
import {
    formatBytes,
    normalizeRelativePath,
    joinPath,
    parentPath,
    basename,
    formatDate,
} from './format';

/* ===========================================================================
 * Module surface
 *
 * The spec requires that `src/format.ts` exports ONLY these six functions and
 * nothing else. This guard test pins that contract so a stray export does not
 * sneak in.
 * ========================================================================= */
describe('format module surface', () => {
    it('exports exactly the six documented functions', () => {
        expect(Object.keys(formatModule).sort()).toEqual(
            ['basename', 'formatBytes', 'formatDate', 'joinPath', 'normalizeRelativePath', 'parentPath'],
        );
    });
});

/* ===========================================================================
 * formatBytes
 *
 * Binary (1024-based) units: B, KB, MB, GB, TB.
 *  - bytes < 1024 render as an integer byte count (e.g. "1023 B").
 *  - bytes >= 1024 render with exactly one decimal place (e.g. "1.5 KB").
 * ========================================================================= */
describe('formatBytes', () => {
    it('formats zero bytes', () => {
        expect(formatBytes(0)).toBe('0 B');
    });

    it('formats a single byte', () => {
        expect(formatBytes(1)).toBe('1 B');
    });

    it('renders values under 1024 as an integer byte count with no decimals', () => {
        expect(formatBytes(1023)).toBe('1023 B');
        expect(formatBytes(512)).toBe('512 B');
    });

    it('renders exactly one kilobyte keeping the ".0" decimal', () => {
        // Spec: 1 decimal when >= 1024, so the trailing .0 is preserved.
        expect(formatBytes(1024)).toBe('1.0 KB');
    });

    it('formats 1536 bytes as 1.5 KB (the documented example)', () => {
        expect(formatBytes(1536)).toBe('1.5 KB');
    });

    it('rounds to one decimal place (2000 -> 2.0 KB)', () => {
        // 2000 / 1024 = 1.953125 -> one decimal rounds up to 2.0
        expect(formatBytes(2000)).toBe('2.0 KB');
    });

    it('formats exactly one megabyte keeping the ".0" decimal (documented example)', () => {
        expect(formatBytes(1048576)).toBe('1.0 MB');
    });

    it('formats 1.5 megabytes', () => {
        expect(formatBytes(1572864)).toBe('1.5 MB'); // 1.5 * 1024 * 1024
    });

    it('formats exactly one gigabyte', () => {
        expect(formatBytes(1073741824)).toBe('1.0 GB'); // 1024 ** 3
    });

    it('formats exactly one terabyte', () => {
        expect(formatBytes(1099511627776)).toBe('1.0 TB'); // 1024 ** 4
    });

    it('does not exceed the TB unit for very large values', () => {
        // 1024 ** 5 would be PB, but the documented unit set stops at TB.
        expect(formatBytes(1099511627776 * 2)).toBe('2.0 TB');
    });
});

/* ===========================================================================
 * normalizeRelativePath
 *
 *  - replace backslashes with '/'
 *  - trim leading/trailing '/'
 *  - collapse repeated '/'
 *  - drop '.' segments and '..' segments (filtered out, NOT resolved)
 *  - return '' for root/empty
 * ========================================================================= */
describe('normalizeRelativePath', () => {
    it('returns empty string for empty input', () => {
        expect(normalizeRelativePath('')).toBe('');
    });

    it('returns empty string for root', () => {
        expect(normalizeRelativePath('/')).toBe('');
    });

    it('returns empty string for a lone backslash (windows root)', () => {
        expect(normalizeRelativePath('\\')).toBe('');
    });

    it('returns empty string for an all-root input', () => {
        expect(normalizeRelativePath('///')).toBe('');
    });

    it('keeps a single clean segment unchanged', () => {
        expect(normalizeRelativePath('foo')).toBe('foo');
    });

    it('keeps multiple clean segments unchanged', () => {
        expect(normalizeRelativePath('foo/bar/baz')).toBe('foo/bar/baz');
    });

    it('trims a leading slash', () => {
        expect(normalizeRelativePath('/foo')).toBe('foo');
    });

    it('trims a trailing slash', () => {
        expect(normalizeRelativePath('foo/')).toBe('foo');
    });

    it('trims both leading and trailing slashes', () => {
        expect(normalizeRelativePath('/foo/bar/')).toBe('foo/bar');
    });

    it('collapses repeated slashes', () => {
        expect(normalizeRelativePath('foo//bar')).toBe('foo/bar');
        expect(normalizeRelativePath('//foo//bar//')).toBe('foo/bar');
    });

    it('replaces backslashes with forward slashes', () => {
        expect(normalizeRelativePath('foo\\bar')).toBe('foo/bar');
        expect(normalizeRelativePath('foo\\bar\\baz')).toBe('foo/bar/baz');
    });

    it('drops a single "." segment', () => {
        expect(normalizeRelativePath('foo/./bar')).toBe('foo/bar');
    });

    it('drops a trailing "." segment', () => {
        expect(normalizeRelativePath('foo/bar/.')).toBe('foo/bar');
    });

    it('drops a leading "." segment', () => {
        expect(normalizeRelativePath('./foo')).toBe('foo');
    });

    it('returns empty string for a lone "." or ".."', () => {
        expect(normalizeRelativePath('.')).toBe('');
        expect(normalizeRelativePath('..')).toBe('');
    });

    it('drops ".." segments rather than resolving them against the parent', () => {
        // Spec wording: "drop '.' segments and '..' segments". A ".." token is
        // filtered out of the segment list; it does NOT pop the previous segment.
        expect(normalizeRelativePath('foo/../bar')).toBe('foo/bar');
        expect(normalizeRelativePath('../foo')).toBe('foo');
    });

    it('drops mixed "." and ".." segments together with repeated slashes', () => {
        expect(normalizeRelativePath('a/../..//b')).toBe('a/b');
    });

    it('returns empty string when every segment is dropped', () => {
        expect(normalizeRelativePath('/./../')).toBe('');
    });

    it('drops multi-level "../../.." sequences entirely (still no resolution)', () => {
        // Reviewer suggestion: multi-level dotdots. Per the "drop" semantics all
        // of these are filtered out, leaving nothing.
        expect(normalizeRelativePath('../../..')).toBe('');
        expect(normalizeRelativePath('../../../')).toBe('');
    });

    it('drops interleaved multi-level dotdots while keeping real segments', () => {
        // segments: [a, .., .., b, ..] -> filter dots -> [a, b]
        expect(normalizeRelativePath('a/../../b/..')).toBe('a/b');
    });
});

/* ===========================================================================
 * joinPath
 *
 * join with a single '/' then run the result through normalizeRelativePath.
 * ========================================================================= */
describe('joinPath', () => {
    it('joins two simple segments', () => {
        expect(joinPath('foo', 'bar')).toBe('foo/bar');
    });

    it('normalizes a trailing slash on the base', () => {
        expect(joinPath('foo/', 'bar')).toBe('foo/bar');
    });

    it('normalizes a leading slash on the name', () => {
        expect(joinPath('foo', '/bar')).toBe('foo/bar');
    });

    it('normalizes slashes on both sides', () => {
        expect(joinPath('foo/', '/bar')).toBe('foo/bar');
    });

    it('returns just the name when the base is empty', () => {
        expect(joinPath('', 'bar')).toBe('bar');
    });

    it('returns just the base when the name is empty', () => {
        // base + '/' + '' -> 'foo/' -> normalize -> 'foo'
        expect(joinPath('foo', '')).toBe('foo');
    });

    it('returns empty string when both parts are empty', () => {
        expect(joinPath('', '')).toBe('');
    });

    it('joins multi-segment paths', () => {
        expect(joinPath('a/b', 'c/d')).toBe('a/b/c/d');
    });

    it('normalizes backslashes in the joined result', () => {
        expect(joinPath('foo\\', 'bar')).toBe('foo/bar');
    });
});

/* ===========================================================================
 * parentPath
 *
 * Normalized parent relative path; '' when already at root.
 * ========================================================================= */
describe('parentPath', () => {
    it('returns empty string for an already-root path', () => {
        expect(parentPath('')).toBe('');
    });

    it('returns empty string for a single-segment path', () => {
        expect(parentPath('foo')).toBe('');
    });

    it('returns the parent of a two-segment path', () => {
        expect(parentPath('foo/bar')).toBe('foo');
    });

    it('returns the parent of a deeper path', () => {
        expect(parentPath('a/b/c')).toBe('a/b');
    });

    it('normalizes before computing the parent', () => {
        expect(parentPath('/foo/bar/')).toBe('foo');
    });

    it('normalizes "." segments before computing the parent', () => {
        expect(parentPath('a/./b')).toBe('a');
    });

    it('normalizes backslashes before computing the parent', () => {
        expect(parentPath('foo\\bar\\baz')).toBe('foo/bar');
    });
});

/* ===========================================================================
 * basename
 *
 * The last segment of the normalized path.
 * ========================================================================= */
describe('basename', () => {
    it('returns empty string for an empty path', () => {
        expect(basename('')).toBe('');
    });

    it('returns the single segment of a shallow path', () => {
        expect(basename('foo')).toBe('foo');
    });

    it('returns the last segment of a multi-segment path', () => {
        expect(basename('foo/bar')).toBe('bar');
    });

    it('returns the last segment of a deeper path', () => {
        expect(basename('a/b/c')).toBe('c');
    });

    it('normalizes leading/trailing slashes before taking the last segment', () => {
        expect(basename('/foo/bar/')).toBe('bar');
    });

    it('normalizes backslashes before taking the last segment', () => {
        expect(basename('foo\\bar')).toBe('bar');
    });

    it('ignores a trailing "." segment when computing the basename', () => {
        expect(basename('foo/bar/.')).toBe('bar');
    });
});

/* ===========================================================================
 * formatDate
 *
 * Parse an ISO date string; return '' for empty/invalid; otherwise render as
 * 'yyyy-MM-dd HH:mm' (local calendar time). The offset-free ISO datetimes used
 * below are parsed as local time, so the expected output is stable regardless
 * of the host time zone for a manual local-getter formatter.
 * ========================================================================= */
describe('formatDate', () => {
    it('returns empty string for an empty input', () => {
        expect(formatDate('')).toBe('');
    });

    it('returns empty string for a non-date string', () => {
        expect(formatDate('not-a-date')).toBe('');
    });

    it('returns empty string for arbitrary garbage', () => {
        expect(formatDate('abc')).toBe('');
    });

    it('does not throw for invalid input', () => {
        expect(() => formatDate('nope')).not.toThrow();
    });

    it('formats a local datetime as yyyy-MM-dd HH:mm', () => {
        expect(formatDate('2023-06-15T09:05:00')).toBe('2023-06-15 09:05');
    });

    it('formats an evening datetime', () => {
        expect(formatDate('2024-02-29T23:59:00')).toBe('2024-02-29 23:59');
    });

    it('pads single-digit month, day, hour and minute with a leading zero', () => {
        expect(formatDate('2023-01-05T08:02:00')).toBe('2023-01-05 08:02');
    });

    it('drops seconds (only year-month-day hour:minute are rendered)', () => {
        expect(formatDate('2023-06-15T09:05:45')).toBe('2023-06-15 09:05');
    });

    it('accepts a UTC "Z" offset and renders the yyyy-MM-dd HH:mm shape', () => {
        // Reviewer suggestion: timezone offsets. A trailing 'Z' makes the input
        // UTC, so the exact local output depends on the host time zone. We
        // therefore assert the format/shape rather than a literal value, and
        // that a valid offset-bearing date is NOT treated as invalid (i.e. the
        // result is a non-empty, properly-shaped string).
        const result = formatDate('2023-06-15T09:05:00Z');
        expect(result).not.toBe('');
        expect(result).toMatch(/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}$/);
    });

    it('accepts a numeric "+HH:MM" offset and renders the yyyy-MM-dd HH:mm shape', () => {
        const result = formatDate('2023-06-15T09:05:00+05:30');
        expect(result).not.toBe('');
        expect(result).toMatch(/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}$/);
    });
});

/**
 * DOM-bound router helper tests.
 *
 * These run in the project-default `happy-dom` environment (see
 * vitest.config.ts) because they exercise `window`, `window.location`, and the
 * `hashchange` event. The pure parsers/serializers are covered separately in
 * `router.test.ts` (pinned to the `node` environment).
 *
 * Independence: every test starts from a clean `window.location.hash` and any
 * listener registered during a test is guaranteed to be removed before the next
 * test runs, even if an assertion throws.
 */
import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { getCurrentRoute, subscribe, navigate } from './router';

describe('getCurrentRoute', () => {
  beforeEach(() => {
    window.location.hash = '';
  });

  it('returns the default browse route when the hash is empty', () => {
    expect(getCurrentRoute()).toEqual({ view: 'browse', path: '', query: '' });
  });

  it('reflects the current browse hash from window.location', () => {
    window.location.hash = '#/browse/docs/2024';
    expect(getCurrentRoute()).toEqual({ view: 'browse', path: 'docs/2024', query: '' });
  });

  it('reflects the current search hash from window.location', () => {
    window.location.hash = '#/search?q=term&path=folder';
    expect(getCurrentRoute()).toEqual({ view: 'search', query: 'term', path: 'folder' });
  });
});

describe('navigate', () => {
  beforeEach(() => {
    window.location.hash = '';
  });

  it('sets window.location.hash to the provided value', () => {
    navigate('#/browse/docs');
    expect(window.location.hash).toBe('#/browse/docs');
  });

  it('updates the location so getCurrentRoute reflects the new route', () => {
    navigate('#/search?q=hi&path=x');
    expect(getCurrentRoute()).toEqual({ view: 'search', query: 'hi', path: 'x' });
  });
});

describe('subscribe', () => {
  // Collect unsubscribe functions so listeners can never leak between tests,
  // even if a test fails mid-way through its assertions.
  const teardowns: Array<() => void> = [];

  beforeEach(() => {
    window.location.hash = '';
  });

  afterEach(() => {
    let teardown: (() => void) | undefined;
    while ((teardown = teardowns.pop()) !== undefined) {
      teardown();
    }
    window.location.hash = '';
  });

  it('invokes the callback when a hashchange event is dispatched', () => {
    const cb = vi.fn();
    teardowns.push(subscribe(cb));

    window.dispatchEvent(new Event('hashchange'));

    expect(cb).toHaveBeenCalledTimes(1);
  });

  it('does not invoke the callback before any hashchange occurs', () => {
    const cb = vi.fn();
    teardowns.push(subscribe(cb));

    expect(cb).not.toHaveBeenCalled();
  });

  it('returns an unsubscribe function that stops further callbacks', () => {
    const cb = vi.fn();
    const unsubscribe = subscribe(cb);
    // Also register it for safety; calling it twice is harmless.
    teardowns.push(unsubscribe);

    window.dispatchEvent(new Event('hashchange'));
    expect(cb).toHaveBeenCalledTimes(1);

    unsubscribe();

    window.dispatchEvent(new Event('hashchange'));
    window.dispatchEvent(new Event('hashchange'));
    expect(cb).toHaveBeenCalledTimes(1);
  });

  it('keeps multiple independent subscriptions isolated', () => {
    const first = vi.fn();
    const second = vi.fn();
    const unsubscribeFirst = subscribe(first);
    teardowns.push(unsubscribeFirst);
    teardowns.push(subscribe(second));

    window.dispatchEvent(new Event('hashchange'));
    expect(first).toHaveBeenCalledTimes(1);
    expect(second).toHaveBeenCalledTimes(1);

    unsubscribeFirst();

    window.dispatchEvent(new Event('hashchange'));
    expect(first).toHaveBeenCalledTimes(1); // unchanged after its removal
    expect(second).toHaveBeenCalledTimes(2); // still active
  });

  it('fires for successive hashchange events while subscribed', () => {
    const cb = vi.fn();
    teardowns.push(subscribe(cb));

    window.dispatchEvent(new Event('hashchange'));
    window.dispatchEvent(new Event('hashchange'));
    window.dispatchEvent(new Event('hashchange'));

    expect(cb).toHaveBeenCalledTimes(3);
  });
});

import { mkdir, copyFile } from 'node:fs/promises';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const rootDir = resolve(__dirname, '..');
const srcDir = resolve(rootDir, 'src');
const outDir = resolve(rootDir, 'wwwroot', 'dist');

async function main() {
  // Ensure output directory exists
  await mkdir(outDir, { recursive: true });

  const srcPath = resolve(srcDir, 'app.css');
  const destPath = resolve(outDir, 'app.css');

  try {
    await copyFile(srcPath, destPath);
  } catch {
    // If src/app.css doesn't exist, exit 0 silently
    process.exit(0);
  }
}

main();

import Event from '../../event/Event.js';
import HTMLElement from '../html-element/HTMLElement.js';
import * as PropertySymbol from '../../PropertySymbol.js';
/**
 * HTML Dialog Element.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/HTMLDialogElement
 */
export default class HTMLDialogElement extends HTMLElement {
    // Internal properties
    [PropertySymbol.returnValue] = '';
    // Events
    oncancel = null;
    onclose = null;
    /**
     * Returns return value.
     *
     * @returns Return value.
     */
    get returnValue() {
        return this[PropertySymbol.returnValue];
    }
    /**
     * Sets return value.
     *
     * @param value Return value.
     */
    set returnValue(value) {
        this[PropertySymbol.returnValue] = value;
    }
    /**
     * Sets the "open" attribute.
     *
     * @param open Open.
     */
    set open(open) {
        if (open) {
            this.setAttribute('open', '');
        }
        else {
            this.removeAttribute('open');
        }
    }
    /**
     * Returns open.
     *
     * @returns Open.
     */
    get open() {
        return this.getAttribute('open') !== null;
    }
    /**
     * Closes the dialog.
     *
     * @param [returnValue] ReturnValue.
